import React, { useState, useEffect } from 'react';

const AuthCard = ({ 
  children, 
  title, 
  subtitle, 
  icon: Icon, 
  footerText, 
  footerLinkText, 
  footerLinkTo 
}) => {
  const [scanKey, setScanKey] = useState(0);
  
  useEffect(() => { 
    setScanKey(k => k + 1); 
  }, []);

  const cardStyles = {
    container: {
      minHeight: '100vh',
      width: '100%',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      padding: '3rem 1.5rem',
      boxSizing: 'border-box',
      background: `radial-gradient(circle at center, var(--bg-secondary) 0%, var(--bg-main) 75%)`,
      position: 'relative',
    },
    glowTop: {
      position: 'fixed', 
      top: '-100px', 
      left: '-100px',
      width: '350px', 
      height: '350px',
      background: 'var(--accent-glow)', 
      borderRadius: '50%',
      filter: 'blur(90px)', 
      opacity: 0.55, 
      pointerEvents: 'none', 
      zIndex: 0,
    },
    glowBottom: {
      position: 'fixed', 
      bottom: '-80px', 
      right: '-80px',
      width: '280px', 
      height: '280px',
      background: 'var(--accent-glow)', 
      borderRadius: '50%',
      filter: 'blur(100px)', 
      opacity: 0.3, 
      pointerEvents: 'none', 
      zIndex: 0,
    },
    card: {
      position: 'relative',
      zIndex: 1,
      width: '100%',
      maxWidth: '360px',
      padding: '2rem',
      borderRadius: '24px',
      backdropFilter: 'blur(24px)',
      WebkitBackdropFilter: 'blur(24px)',
      background: 'var(--surface-glass)',
      border: '1px solid var(--surface-border)',
      boxShadow: 'var(--shadow-elevated)',
      overflow: 'hidden',
      transition: 'box-shadow 0.4s ease, border-color 0.4s ease',
    },
    header: {
      textAlign: 'center', 
      marginBottom: '2rem',
    },
    iconContainer: {
      display: 'flex', 
      justifyContent: 'center', 
      marginBottom: '0.875rem',
    },
    iconBox: {
      width: '48px', 
      height: '48px', 
      borderRadius: '14px',
      background: 'var(--accent-muted)',
      border: '1px solid var(--accent-primary)',
      display: 'flex', 
      alignItems: 'center', 
      justifyContent: 'center',
      boxShadow: '0 0 20px var(--accent-glow)',
    },
    title: {
      fontSize: '1.5rem', 
      fontWeight: 300,
      letterSpacing: '-0.02em',
      color: 'var(--text-primary)',
      margin: '0 0 0.35rem',
    },
    subtitle: {
      fontSize: '0.6rem', 
      textTransform: 'uppercase',
      letterSpacing: '0.22em', 
      color: 'var(--text-muted)', 
      margin: 0,
    },
    footer: {
      marginTop: '1.5rem',
      paddingTop: '1.25rem',
      borderTop: '1px solid var(--surface-border)',
      textAlign: 'center',
    },
    footerText: {
      fontSize: '0.6rem', 
      textTransform: 'uppercase',
      letterSpacing: '0.2em', 
      color: 'var(--text-muted)', 
      margin: 0,
    },
  };

  const handleMouseEnter = (e) => {
    e.currentTarget.style.boxShadow = `0 0 40px var(--accent-glow), var(--shadow-elevated)`;
    e.currentTarget.style.borderColor = 'var(--accent-primary)';
  };

  const handleMouseLeave = (e) => {
    e.currentTarget.style.boxShadow = 'var(--shadow-elevated)';
    e.currentTarget.style.borderColor = 'var(--surface-border)';
  };

  return (
    <div style={cardStyles.container}>
      <div aria-hidden="true" style={cardStyles.glowTop} />
      <div aria-hidden="true" style={cardStyles.glowBottom} />

      <div
        className="reveal-node"
        style={cardStyles.card}
        onMouseEnter={handleMouseEnter}
        onMouseLeave={handleMouseLeave}
      >
        <span key={scanKey} className="animate-laser" aria-hidden="true" />

        <div style={cardStyles.header}>
          <div style={cardStyles.iconContainer}>
            <div style={cardStyles.iconBox}>
              <Icon size={22} color="var(--accent-primary)" />
            </div>
          </div>
          <h1 style={cardStyles.title}>{title}</h1>
          <p style={cardStyles.subtitle}>{subtitle}</p>
        </div>

        {children}

        {footerText && (
          <div style={cardStyles.footer}>
            <p style={cardStyles.footerText}>
              {footerText}
            </p>
          </div>
        )}
      </div>
    </div>
  );
};

export default AuthCard;
